module RefModule (
    input clk,
    input reset_n,
    input en,
    input hold,
    output reg [7:0] q);

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or negedge reset_n or posedge dbg_halt) begin
    if (!reset_n)
        q <= 8'b00000000;
    else if (hold)
        q <= q;
    else if (en)
        q <= q - 1;
end

endmodule
